import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const [workers, setWorkers] = useState([]);
  const [requests, setRequests] = useState([]);

  const [search, setSearch] = useState("");
  const [location, setLocation] = useState("");
  const [date, setDate] = useState("");

  const [time1, setTime1] = useState("");
  const [time2, setTime2] = useState("");
  const [time3, setTime3] = useState("");

  const user = JSON.parse(localStorage.getItem("user"));

  // =========================
  // FETCH REQUESTS
  // =========================
  const fetchRequests = async () => {

    const res = await axios.get(
      `http://localhost:5000/api/request/customer/${user.name}`
    );

    setRequests(res.data);
  };

  useEffect(() => {
    fetchRequests();
  }, []);

  // =========================
  // SEARCH WORKERS
  // =========================
  const searchWorkers = async () => {

    const res = await axios.get(
      "http://localhost:5000/api/auth/workers"
    );

    const filtered = res.data.filter(w =>
      w.skills?.some(skill =>
        skill.toLowerCase().includes(search.toLowerCase())
      ) &&
      w.city?.toLowerCase().includes(location.toLowerCase())
    );

    setWorkers(filtered);
  };

  // =========================
  // SEND REQUEST
  // =========================
  const sendRequest = async (worker) => {

    await axios.post("http://localhost:5000/api/request/send", {
      customerName: user.name,
      customerId: user._id,

      labourId: worker._id,
      labourName: worker.name,

      workType: search,
      location,

      date,
      timings: [time1, time2, time3]
    });

    fetchRequests();
  };

  // =========================
  // MATCH REQUEST
  // =========================
  const getReq = (workerId) => {

    return requests.find(r =>
      String(r.labourId) === String(workerId)
    );
  };

  // =========================
  // CUSTOMER DECISION
  // =========================
  const decision = async (id, value) => {

    await axios.put(
      `http://localhost:5000/api/request/customer-decision/${id}`,
      { decision: value }
    );

    fetchRequests();
  };

  // =========================
  // FEEDBACK
  // =========================
  const feedback = async (id) => {

    const rating = prompt("Rating (1-5)");
    const comment = prompt("Comment");

    await axios.put(
      `http://localhost:5000/api/request/feedback/${id}`,
      { rating, comment }
    );

    fetchRequests();
  };

  return (

    <div>
      <Navbar />

      <div style={{ padding: 20 }}>

        <h2>Find Workers</h2>

        {/* SEARCH */}
        <input placeholder="Work" onChange={e => setSearch(e.target.value)} />
        <input placeholder="Location" onChange={e => setLocation(e.target.value)} />
        <input type="date" onChange={e => setDate(e.target.value)} />

        <button onClick={searchWorkers}>Search</button>

        {/* WORKERS */}
        {workers.map(w => {

          const req = getReq(w._id);

          return (

            <div key={w._id} style={{ border: "1px solid gray", margin: 10, padding: 10 }}>

              <h3>{w.name}</h3>
              <p>{w.skills?.join(", ")}</p>
              <p>{w.city}</p>

              {/* REQUEST STATUS */}
              {req && (
                <div>

                  <p>Status: {req.status}</p>
                  <p>Price: {req.labourPrice}</p>
                  <p>Labour Response: {req.labourResponse}</p>
                  <p>Customer Decision: {req.customerDecision}</p>

                  {/* CUSTOMER DECISION */}
                  {req.labourResponse === "Accepted" &&
                    req.customerDecision === "Waiting" && (
                    <>
                      <button onClick={() => decision(req._id, "Accepted")}>Accept</button>
                      <button onClick={() => decision(req._id, "Rejected")}>Reject</button>
                    </>
                  )}

                  {/* FEEDBACK */}
                  {req.customerDecision === "Accepted" && (
                    <button onClick={() => feedback(req._id)}>
                      Give Feedback
                    </button>
                  )}

                </div>
              )}

              {!req && (
                <button onClick={() => sendRequest(w)}>
                  Send Request
                </button>
              )}

            </div>
          );
        })}

      </div>
    </div>
  );
}
